arguments.new_str:
protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF Core 9 changed the default discriminator property from "Discriminator" to "$type".
        // Preserve the old name so existing 500K documents remain readable and direct SQL
        // queries referencing c.Discriminator continue to work.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9 changed id generation from "Product|123" to just "123".
        // Preserve the old compound format so existing documents can be found by key.
        entity.HasRootDiscriminatorInJsonId(true);

        // HasIndex is removed — EF Core 9 Cosmos provider throws at startup.
        // Manage indexing via the Cosmos DB indexing policy (Azure Portal / Bicep / Terraform).
    });
}

arguments.old_str:
class CosmosQuery
{
    void FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";
        // Also uses sync APIs
        var products = ctx.Products.Where(p => p.Sku == "ABC").ToList();
    }
}

arguments.new_str:
using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    // EF Core 9 Cosmos provider no longer supports synchronous I/O — use async.
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — still works because we preserved "Discriminator" (not "$type")
        // via HasDiscriminator<string>("Discriminator") in OnModelCreating.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // ToList() throws in EF Core 9 Cosmos — replaced with ToListAsync().
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

